def scrape_bandi_statici() -> List[Dict]:
    """Carica tutti i bandi dal database statico completo (300+)."""
    print("      → Caricamento database 300+ bandi...")
    bandi = []
    for bando_info in BANDI_COMPLETI:
        bando = {
            **bando_info,
            'stato': 'aperto',
            'fonte': bando_info['ente'],
            'hash_id': get_hash(bando_info['titolo']),
            'attivo': True
        }
        bandi.append(bando)
    print(f"        ✓ {len(bandi)} bandi caricati")
    return bandi
